var lines = msg.payload.split('\n');
var parsedRecords = [];

for(var i=0; i<lines.length; i++) {
    if(lines[i].trim() !== '') {
        var parts = lines[i].split(' | ');
        var record = {
            timestamp: parts[0],
            target: parts[1].split('=')[1],
            qty: parts[2].split('=')[1],
            operator: parts[3].split('=')[1],
            status: parts[4].split('=')[1].replace('\r', '')
        };
        parsedRecords.push(record);
    }
}
msg.payload = parsedRecords;
return msg;
